mapper.select:
select s.*,c.name clazzName from student s left join clazz c on s.clazz_id = c.id
and s.name like concat('%',#{name},'%')
and s.degree >= #{degree}
and s.clazz_id = #{clazzId}

select
ifnull(c.name,'其他') clazzList,count(*) dataList
from student s left join clazz c on s.clazz_id = c.id group by c.name order by dataList desc ;
